class BoundedBuffer<T> {
    private final Queue<T> queue = new LinkedList<>();
    private final int capacity;

    BoundedBuffer(int capacity) { this.capacity = capacity; }

    public synchronized void produce(T item) throws InterruptedException {
        while (queue.size() == capacity) {
            wait(); // buffer full — release lock, wait
        }
        queue.add(item);
        notifyAll(); // wake consumers
    }

    public synchronized T consume() throws InterruptedException {
        while (queue.isEmpty()) {
            wait(); // buffer empty — release lock, wait
        }
        T item = queue.poll();
        notifyAll(); // wake producers
        return item;
    }
}
// Modern alternative: use BlockingQueue — handles all synchronization internally

// ReadWriteLock — multiple readers OR single writer
ReadWriteLock rwLock = new ReentrantReadWriteLock();

void readData() {
    rwLock.readLock().lock(); // multiple threads can hold this
    try { return cache.get(key); }
    finally { rwLock.readLock().unlock(); }
}

void writeData() {
    rwLock.writeLock().lock(); // exclusive — blocks readers AND writers
    try { cache.put(key, value); }
    finally { rwLock.writeLock().unlock(); }
}

// StampedLock — optimistic reading (Java 8)
StampedLock sl = new StampedLock();

double readOptimistic() {
    long stamp = sl.tryOptimisticRead(); // no actual lock!
    double x = this.x, y = this.y;       // read fields
    if (!sl.validate(stamp)) {            // was there a write?
        stamp = sl.readLock();            // fallback to pessimistic
        try { x = this.x; y = this.y; }
        finally { sl.unlockRead(stamp); }
    }
    return Math.sqrt(x * x + y * y);
}

