synchronized (lock) { ... }

// BAD — exception leaves lock held forever
lock.lock();
riskyOperation(); // throws!
lock.unlock(); // never reached!

// GOOD — finally guarantees unlock
lock.lock();
try {
    riskyOperation();
} finally {
    lock.unlock(); // always executed
}

