// ForkJoinPool — recursive divide and conquer
class SumTask extends RecursiveTask<Long> {
    private final long[] array;
    private final int from, to;
    private static final int THRESHOLD = 1000;

    protected Long compute() {
        if (to - from <= THRESHOLD) {
            long sum = 0;
            for (int i = from; i < to; i++) sum += array[i];
            return sum; // base case
        }
        int mid = (from + to) / 2;
        SumTask left = new SumTask(array, from, mid);
        SumTask right = new SumTask(array, mid, to);
        left.fork();           // submit to pool
        long rightResult = right.compute(); // compute in current thread
        long leftResult = left.join();       // wait for forked result
        return leftResult + rightResult;
    }
}

// 4 Rejection Policies (when queue is full)
// AbortPolicy (default)     → throws RejectedExecutionException
// DiscardPolicy             → silently drops the task
// DiscardOldestPolicy       → drops oldest queued task, retries
// CallerRunsPolicy          → executes in the submitting thread (backpressure)

// BlockingQueue — all synchronization handled internally
BlockingQueue<Task> queue = new ArrayBlockingQueue<>(100);

// Producer thread
void produce(Task task) throws InterruptedException {
    queue.put(task);  // blocks if queue is full — backpressure!
}

// Consumer thread
void consume() throws InterruptedException {
    while (true) {
        Task task = queue.take(); // blocks if queue is empty
        process(task);
    }
}

// Non-blocking alternatives
queue.offer(task);               // returns false if full
queue.offer(task, 5, TimeUnit.SECONDS); // waits up to 5s
queue.poll();                    // returns null if empty
queue.poll(5, TimeUnit.SECONDS); // waits up to 5s

